css:
.print-heading {
  text-align: center;
  margin-bottom: 30px;
}

.print-heading h1 {
  margin: 0 0 4px;
  font-size: 15pt;
  font-weight: 700;
}

.print-heading p {
  margin: 4px 0 0;
}

.section-heading {
  margin-top: 22px;
  margin-bottom: 10px;
  padding-bottom: 5px;
  border-bottom: 1px solid #b40000;
  font-size: 12pt;
  font-weight: 600;
  page-break-after: avoid;
}

table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 16px;
}

table th,
table td {
  padding: 8px;
  vertical-align: top;
  border: 1px solid #ddd;
}

table th {
  display: none;
}

/* Signature block */
.signatures {
  margin-top: 34px;
  page-break-inside: avoid;
}

.signatures table {
  width: 100%;
  border-collapse: collapse;
}

.signatures td {
  width: 50%;
  padding: 18px 24px 14px 0;
  border: none;
  vertical-align: bottom;
}

.signatures td:nth-child(even) {
  padding-right: 0;
}

.signature-space {
  height: 34px;
}

.signature-line {
  width: 100%;
  margin-bottom: 5px;
  border-top: 1px solid #333;
}

.signatures p {
  margin: 0;
  font-size: 9pt;
}

@page {
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
